function data = generate_synthetic_shp_data(params)
%GENERATE_SYNTHETIC_SHP_DATA
% Generate synthetic data for SHP / CRSHP / CVaR-CRSHP experiments.
%
% This generator supports the three-point moment ambiguity set:
%
%   b_i in {bLower_i, mu_i, bUpper_i},
%   E[b_i] = mu_i,
%   dLower_i <= E[|b_i - mu_i|] <= delta_i.
%
% The worst-case marginal distribution in Proposition 2 is obtained by using
% d_i = dLower_i. A nominal distribution for classical SHP is generated by
% choosing dNominal_i in [dLower_i, delta_i].

    if nargin < 1
        params = struct();
    end

    % ------------------------------------------------------------
    % Defaults
    % ------------------------------------------------------------
    params = set_default(params, 'seed', []);
    params = set_default(params, 'n', 20);
    params = set_default(params, 'kMode', 'half');     % 'half', 'third', or specify k
    params = set_default(params, 'k', []);
    
    % First-stage price.
    % aMode = 'uniform': a_i ~ U[aLow, aHigh]
    % aMode = 'beta_mu': a_i = beta * mu_i + epsilon_i
    params = set_default(params, 'aMode', 'uniform');
    params = set_default(params, 'aLow', 1);
    params = set_default(params, 'aHigh', 10);
    params = set_default(params, 'beta', 0.8);
    params = set_default(params, 'epsilonLow', -5);
    params = set_default(params, 'epsilonHigh', 5);

    % Three-point support generation
    params = set_default(params, 'muLow', 2);
    params = set_default(params, 'muHigh', 12);
    params = set_default(params, 'lowerGapLow', 1);
    params = set_default(params, 'lowerGapHigh', 5);
    params = set_default(params, 'upperGapLow', 1);
    params = set_default(params, 'upperGapHigh', 5);

    % MAD level controls
    params = set_default(params, 'dLowerRatioLow', 0.20);
    params = set_default(params, 'dLowerRatioHigh', 0.50);
    params = set_default(params, 'deltaRatioLow', 0.60);
    params = set_default(params, 'deltaRatioHigh', 0.95);

    % How to choose nominal MAD dNominal in [dLower, delta]
    % options: 'middle', 'random', 'upper', 'lower'
    params = set_default(params, 'nominalMADMode', 'middle');

    % Scenario generation
    params = set_default(params, 'generateNominalScenarios', true);
    params = set_default(params, 'T', 500);
    params = set_default(params, 'generateTestScenarios', true);
    params = set_default(params, 'Ttest', 1000);

    % Dependence mode for sampled scenarios:
    % 'independent', 'comonotone', 'group_comonotone'
    params = set_default(params, 'dependenceMode', 'independent');
    params = set_default(params, 'numGroups', 3);

    % Optional full independent product distribution
    params = set_default(params, 'buildFullProduct', false);
    params = set_default(params, 'maxProductSupport', 1e5);

    if ~isempty(params.seed)
        rng(params.seed);
    end

    n = params.n;

    % ------------------------------------------------------------
    % Budget k
    % ------------------------------------------------------------
    if ~isempty(params.k)
        k = params.k;
    else
        switch builtin('lower', params.kMode)
            case 'half'
                k = floor(n/2);
            case 'third'
                k = floor(n/3);
            otherwise
                error('Unsupported kMode: %s. Use half, third, or specify params.k.', params.kMode);
        end
    end

    % ------------------------------------------------------------
    % Generate three-point supports
    % ------------------------------------------------------------
    mu = params.muLow + (params.muHigh - params.muLow) * rand(n,1);

    lowerGap = params.lowerGapLow + ...
        (params.lowerGapHigh - params.lowerGapLow) * rand(n,1);

    upperGap = params.upperGapLow + ...
        (params.upperGapHigh - params.upperGapLow) * rand(n,1);

    bLower = mu - lowerGap;
    bUpper = mu + upperGap;

    % ------------------------------------------------------------
    % First-stage prices
    % ------------------------------------------------------------
    switch builtin('lower', params.aMode)
        case 'uniform'
            a = params.aLow + (params.aHigh - params.aLow) * rand(n,1);
        case 'beta_mu'
            epsilon = params.epsilonLow + ...
                (params.epsilonHigh - params.epsilonLow) * rand(n,1);
            a = params.beta .* mu + epsilon;
        otherwise
            error('Unsupported aMode: %s. Use uniform or beta_mu.', params.aMode);
    end

    A = mu - bLower;
    B = bUpper - mu;

    % Feasible maximum MAD for three-point distribution with mean mu
    dMax = 2 .* A .* B ./ (A + B);

    % ------------------------------------------------------------
    % Generate dLower and delta
    % ------------------------------------------------------------
    dLowerRatio = params.dLowerRatioLow + ...
        (params.dLowerRatioHigh - params.dLowerRatioLow) * rand(n,1);

    deltaRatio = params.deltaRatioLow + ...
        (params.deltaRatioHigh - params.deltaRatioLow) * rand(n,1);

    % Ensure deltaRatio >= dLowerRatio
    deltaRatio = max(deltaRatio, dLowerRatio + 1e-4);
    deltaRatio = min(deltaRatio, 0.999);

    dLower = dLowerRatio .* dMax;
    delta = deltaRatio .* dMax;

    % ------------------------------------------------------------
    % Choose nominal MAD level dNominal in [dLower, delta]
    % ------------------------------------------------------------
    switch builtin('lower', params.nominalMADMode)
        case 'middle'
            dNominal = 0.5 * (dLower + delta);
        case 'random'
            dNominal = dLower + rand(n,1) .* (delta - dLower);
        case 'upper'
            dNominal = delta;
        case 'lower'
            dNominal = dLower;
        otherwise
            error('Unsupported nominalMADMode: %s.', params.nominalMADMode);
    end

    % ------------------------------------------------------------
    % Build marginal distributions
    % ------------------------------------------------------------
    supports = cell(n,1);
    pWorst = cell(n,1);
    pNominal = cell(n,1);

    probWorstMat = zeros(n,3);
    probNominalMat = zeros(n,3);

    for i = 1:n
        supports{i} = [bLower(i), mu(i), bUpper(i)];

        pW = three_point_probs(bLower(i), mu(i), bUpper(i), dLower(i));
        pN = three_point_probs(bLower(i), mu(i), bUpper(i), dNominal(i));

        pWorst{i} = pW;
        pNominal{i} = pN;

        probWorstMat(i,:) = pW(:)';
        probNominalMat(i,:) = pN(:)';
    end

    % ------------------------------------------------------------
    % Generate scenario matrices if requested
    % ------------------------------------------------------------
    X_nominal = [];
    X_test = [];

    if params.generateNominalScenarios
        X_nominal = sample_from_marginals(supports, pNominal, params.T, ...
            params.dependenceMode, params.numGroups);
    end

    if params.generateTestScenarios
        X_test = sample_from_marginals(supports, pNominal, params.Ttest, ...
            params.dependenceMode, params.numGroups);
    end

    % ------------------------------------------------------------
    % Optional: build full independent product distribution for small n
    % ------------------------------------------------------------
    fullProduct = struct();
    fullProduct.available = false;
    fullProduct.support = [];
    fullProduct.prob = [];

    if params.buildFullProduct
        productSize = 3^n;
        if productSize <= params.maxProductSupport
            [Xprod, pprod] = build_independent_product_distribution(supports, pNominal);
            fullProduct.available = true;
            fullProduct.support = Xprod;
            fullProduct.prob = pprod;
        else
            warning('Full product support size 3^n = %.3g exceeds maxProductSupport. Skipped.', productSize);
        end
    end

    % ------------------------------------------------------------
    % Diagnostics
    % ------------------------------------------------------------
    diagnostics = check_three_point_marginals(bLower, mu, bUpper, ...
        dLower, delta, dNominal, pWorst, pNominal);

    % ------------------------------------------------------------
    % Output
    % ------------------------------------------------------------
    data = struct();

    data.n = n;
    data.k = k;
    data.a = a;

    data.bLower = bLower;
    data.mu = mu;
    data.bUpper = bUpper;

    % 为了兼容之前可能已经写的代码，也保留 lower/upper 字段名
    data.lower = bLower;
    data.upper = bUpper;

    data.dLower = dLower;
    data.delta = delta;
    data.dNominal = dNominal;
    data.dMax = dMax;

    data.supports = supports;
    data.pWorst = pWorst;
    data.pNominal = pNominal;

    data.probWorstMat = probWorstMat;
    data.probNominalMat = probNominalMat;

    data.X_nominal = X_nominal;
    data.X_test = X_test;

    data.fullProduct = fullProduct;

    data.meta = struct();
    data.meta.params = params;
    data.meta.diagnostics = diagnostics;
    data.meta.description = ...
        'Synthetic three-point moment ambiguity data for SHP / CRSHP / CVaR-CRSHP.';
end

% =====================================================================
% Helper: compute three-point probabilities
% =====================================================================
function p = three_point_probs(bLower, mu, bUpper, d)
    A = mu - bLower;
    B = bUpper - mu;

    if A <= 0 || B <= 0
        error('Invalid support: need bLower < mu < bUpper.');
    end

    pL = d / (2*A);
    pU = d / (2*B);
    pM = 1 - pL - pU;

    tol = 1e-10;
    if pL < -tol || pM < -tol || pU < -tol
        error('Infeasible d for three-point distribution. Probabilities are negative.');
    end

    % Numerical cleanup
    p = [max(pL,0), max(pM,0), max(pU,0)];
    p = p / sum(p);
end

% =====================================================================
% Helper: sample scenarios from marginal distributions
% =====================================================================
function X = sample_from_marginals(supports, probs, T, dependenceMode, numGroups)
    n = numel(supports);
    X = zeros(T,n);

    switch builtin('lower', dependenceMode)
        case 'independent'
            U = rand(T,n);

        case 'comonotone'
            u = rand(T,1);
            U = repmat(u, 1, n);

        case 'group_comonotone'
            U = zeros(T,n);
            groupLabels = assign_groups(n, numGroups);
            for g = 1:numGroups
                idx = find(groupLabels == g);
                u = rand(T,1);
                U(:,idx) = repmat(u, 1, numel(idx));
            end

        otherwise
            error('Unsupported dependenceMode: %s.', dependenceMode);
    end

    for i = 1:n
        X(:,i) = inverse_discrete_cdf(U(:,i), supports{i}, probs{i});
    end
end

% =====================================================================
% Helper: inverse CDF for discrete distribution
% =====================================================================
function x = inverse_discrete_cdf(u, support, prob)
    cdf = cumsum(prob(:));
    x = zeros(size(u));

    for t = 1:numel(u)
        idx = find(u(t) <= cdf, 1, 'first');
        x(t) = support(idx);
    end
end

% =====================================================================
% Helper: assign assets to groups
% =====================================================================
function groupLabels = assign_groups(n, numGroups)
    groupLabels = zeros(n,1);
    for i = 1:n
        groupLabels(i) = mod(i-1, numGroups) + 1;
    end
end

% =====================================================================
% Helper: build full independent product distribution
% Only for small n.
% =====================================================================
function [Xprod, pprod] = build_independent_product_distribution(supports, probs)
    n = numel(supports);
    total = 3^n;

    Xprod = zeros(total, n);
    pprod = zeros(total, 1);

    for row = 1:total
        tmp = row - 1;
        probRow = 1;

        for i = 1:n
            state = mod(tmp, 3) + 1;
            tmp = floor(tmp / 3);

            Xprod(row,i) = supports{i}(state);
            probRow = probRow * probs{i}(state);
        end

        pprod(row) = probRow;
    end

    pprod = pprod / sum(pprod);
end

% =====================================================================
% Helper: check moment conditions
% =====================================================================
function diagnostics = check_three_point_marginals(bLower, mu, bUpper, ...
    dLower, delta, dNominal, pWorst, pNominal)

    n = numel(mu);

    meanWorst = zeros(n,1);
    madWorst = zeros(n,1);
    meanNominal = zeros(n,1);
    madNominal = zeros(n,1);

    for i = 1:n
        supp = [bLower(i), mu(i), bUpper(i)];

        pW = pWorst{i};
        meanWorst(i) = sum(pW .* supp);
        madWorst(i) = sum(pW .* abs(supp - mu(i)));

        pN = pNominal{i};
        meanNominal(i) = sum(pN .* supp);
        madNominal(i) = sum(pN .* abs(supp - mu(i)));
    end

    diagnostics = struct();

    diagnostics.maxMeanErrorWorst = max(abs(meanWorst - mu));
    diagnostics.maxMADErrorWorst = max(abs(madWorst - dLower));

    diagnostics.maxMeanErrorNominal = max(abs(meanNominal - mu));
    diagnostics.maxMADErrorNominal = max(abs(madNominal - dNominal));

    diagnostics.nominalMADAboveLower = all(dNominal >= dLower - 1e-8);
    diagnostics.nominalMADBelowDelta = all(dNominal <= delta + 1e-8);

    diagnostics.meanWorst = meanWorst;
    diagnostics.madWorst = madWorst;
    diagnostics.meanNominal = meanNominal;
    diagnostics.madNominal = madNominal;
end

% =====================================================================
% Helper: set default
% =====================================================================
function s = set_default(s, fieldName, defaultValue)
    if ~isfield(s, fieldName) || isempty(s.(fieldName))
        s.(fieldName) = defaultValue;
    end
end
